import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.chrome.ChromeDriver;
public class UISelector {
  public static void main(String[] args) {
    WebDriver driver = new ChromeDriver();
    String xpath = "//div[@class='ui-selectee']";
    WebElement element = driver.findElement(By.xpath(xpath));
    UISelector selector = new UISelector(element);
    System.out.println("UISelector: " + selector.getDescription());
    System.out.println("XPath: " + xpath);
  }
  private static class UISelector {
    private WebElement element;
    private String description;
    private By by;
    public UISelector(WebElement element) {
      this.element = element;
      this.by = element.getAttribute("by");
      this.description = element.getAttribute("description");
    }
    public String getDescription() {
      return description;
    }
    public UISelector setDescription(String description) {
      this.description = description;
      return this;
    }
    public UISelector setBy(By by) {
      this.by = by;
      return this;
    }
    public String getBy() {
      return by;
    }
    public String getDescription() {
      return description;
    }
    public WebElement getElement() {
      return element;
    }
  }
}
```
